#include<bits/stdc++.h>
using namespace std;
int n,q,a[100010],siz[6200010],ch[6200010][2],cnt,d[100010];
int rt1[100010],lg[100010],rt2[100010],ldfn[100010],rdfn[100010],dfncnt,fa[100010][21];
vector<int> mp[100010];
void insert(int &rt,int x,int j)
{
    ch[++cnt][0]=ch[rt][0];
    ch[cnt][1]=ch[rt][1];
    siz[cnt]=siz[rt];
    rt=cnt;
    siz[rt]++;
    if(j!=-1)
    {
        insert(ch[rt][(x>>j)&1],x,j-1);
    }
}
void dfs(int x,int f=0)
{
    ldfn[x]=++dfncnt;
    fa[x][0]=f;
    d[x]=d[f]+1;
    insert(rt1[dfncnt]=rt1[dfncnt-1],a[x],29);
    insert(rt2[x]=rt2[f],a[x],29);
    for(int i=1;i<=lg[d[x]];i++)
    {
        fa[x][i]=fa[fa[x][i-1]][i-1];
    }
    for(int i:mp[x])
    {
        if(i!=f)
        {
            dfs(i,x);
        }
    }
    rdfn[x]=dfncnt;
}
int lca(int x,int y)
{
    if(d[x]<d[y])
    {
        swap(x,y);
    }
    while(d[x]>d[y])
    {
        x=fa[x][lg[d[x]-d[y]]];
    }
    if(x==y)
    {
        return x;
    }
    for(int i=lg[d[x]];i>=0;i--)
    {
        if(fa[x][i]!=fa[y][i])
        {
            x=fa[x][i];
            y=fa[y][i];
        }
    }
    return fa[x][0];
}
int query(int rt1,int rt2,int x,int j)
{
    if(j==-1)
    {
        return 0;
    }
    int p=((x>>j)&1)^1;
    if(siz[ch[rt1][p]]!=siz[ch[rt2][p]])
    {
        return (query(ch[rt1][p],ch[rt2][p],x,j-1)|(1<<j));
    }
    else
    {
        return query(ch[rt1][p^1],ch[rt2][p^1],x,j-1);
    }
}
int main()
{
    scanf("%d%d",&n,&q);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    for(int i=2;i<=n;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        mp[x].push_back(y);
        mp[y].push_back(x);
        lg[i]=__lg(i);
    }
    dfs(1);
    while(q--)
    {
        int op,x,y,z;
        scanf("%d%d%d",&op,&x,&y);
        if(op==1)
        {
            printf("%d\n",query(rt1[rdfn[x]],rt1[ldfn[x]-1],y,29));
        }
        else
        {
            scanf("%d",&z);
            int l=fa[lca(x,y)][0];
            printf("%d\n",max(query(rt2[x],rt2[l],z,29),query(rt2[y],rt2[l],z,29)));
        }
    }
    return 0;
}
